import numpy as np
from scipy.optimize import minimize

def _valid(c, r, n, tol=1e-6):
    if np.any(c[:,0]-r<-tol) or np.any(c[:,0]+r>1+tol): return False
    if np.any(c[:,1]-r<-tol) or np.any(c[:,1]+r>1+tol): return False
    ii, jj = np.triu_indices(n, 1)
    return np.all(np.sqrt(((c[ii]-c[jj])**2).sum(1)) >= r[ii]+r[jj]-tol)

def construct_packing():
    n = 26
    ii, jj = np.triu_indices(n, 1)

    def fv(x): return -np.sum(np.exp(x[2*n:]))
    def wv(x):
        cc, rr = x[:2*n].reshape(n,2), np.exp(x[2*n:])
        return np.r_[cc[:,0]-rr, 1-cc[:,0]-rr, cc[:,1]-rr, 1-cc[:,1]-rr]
    def sv(x):
        cc, rr = x[:2*n].reshape(n,2), np.exp(x[2*n:])
        return np.sqrt(((cc[ii]-cc[jj])**2).sum(1)) - rr[ii] - rr[jj]
    cons = [{'type':'ineq','fun':wv},{'type':'ineq','fun':sv}]

    def _hex(r0, rows, offs):
        pts = []
        dx, dy = 2*r0, r0*3**0.5
        for i, cnt in enumerate(rows):
            y = r0 + i*dy
            for j in range(cnt):
                pts.append([r0 + offs[i]*r0 + j*dx, y])
        c = np.array(pts[:n])
        sc = min(1/(c[:,0].max()+r0), 1/(c[:,1].max()+r0))
        return c*sc, np.full(n, r0*sc)

    def _opt(c, radii):
        # Uniform first
        def fu(x): return -n*np.exp(x[-1])
        def wu(x):
            cc, rr = x[:2*n].reshape(n,2), np.exp(x[-1])
            return np.r_[cc[:,0]-rr, 1-cc[:,0]-rr, cc[:,1]-rr, 1-cc[:,1]-rr]
        def su(x):
            cc, rr = x[:2*n].reshape(n,2), np.exp(x[-1])
            return np.sqrt(((cc[ii]-cc[jj])**2).sum(1)) - 2*rr
        try:
            res = minimize(fu, np.r_[c.ravel(), np.log(radii[0])], method='SLSQP',
                constraints=[{'type':'ineq','fun':wu},{'type':'ineq','fun':su}],
                options={'maxiter':4000,'ftol':1e-14})
            cu = res.x[:2*n].reshape(n,2); ru = np.full(n, np.exp(res.x[-1]))
            if _valid(cu, ru, n): c, radii = cu, ru
        except: pass
        # Variable
        xp = np.r_[c.ravel(), np.log(radii)]
        for ftol in [1e-10, 1e-12, 1e-14]:
            try:
                res = minimize(fv, xp, method='SLSQP', constraints=cons, options={'maxiter':8000,'ftol':ftol})
                cr, rr = res.x[:2*n].reshape(n,2), np.exp(res.x[2*n:])
                if _valid(cr,rr,n) and np.sum(rr)>np.sum(radii):
                    c, radii = cr.copy(), rr.copy(); xp = res.x
            except: pass
        return c, radii

    best_c, best_r, best_s = None, None, 0
    for r0, rows, offs in [
        (0.10127,[6,5,6,5,4],[0,1,0,1,0]), (0.1013,[5,6,5,6,4],[1,0,1,0,0]),
        (0.1013,[6,5,6,5,4],[1,0,1,0,0]), (0.1010,[6,5,6,5,4],[0,1,0,1,0]),
        (0.1015,[5,5,6,5,5],[0,1,0,1,0]), (0.1008,[6,6,5,5,4],[0,0,1,1,0]),
        (0.1020,[6,5,5,5,5],[0,1,0,1,0]), (0.1005,[6,5,6,5,4],[0,1,0,1,1]),
    ]:
        c, radii = _hex(r0, rows, offs)
        c, radii = _opt(c, radii)
        s = np.sum(radii)
        if s > best_s and _valid(c, radii, n):
            best_c, best_r, best_s = c.copy(), radii.copy(), s

    for seed in range(40):
        np.random.seed(seed+7)
        xp = np.r_[best_c.ravel(), np.log(best_r)]
        sc = 0.0005*(1+(seed%12))
        xp[:2*n] += np.random.randn(2*n)*sc
        if seed > 15: xp[2*n:] += np.random.randn(n)*0.01
        if seed > 28:
            i,j = np.random.choice(n, 2, replace=False)
            xp[2*i:2*i+2], xp[2*j:2*j+2] = xp[2*j:2*j+2].copy(), xp[2*i:2*i+2].copy()
        try:
            res = minimize(fv, xp, method='SLSQP', constraints=cons, options={'maxiter':8000,'ftol':1e-14})
            cr, rr = res.x[:2*n].reshape(n,2), np.exp(res.x[2*n:])
            if _valid(cr,rr,n) and np.sum(rr)>best_s:
                best_c, best_r, best_s = cr.copy(), rr.copy(), np.sum(rr)
        except: pass

    return best_c, best_r, float(best_s)
# EVOLVE-BLOCK-END

def run_packing():
    centers, radii, sum_radii = construct_packing()
    return centers, radii, sum_radii

if __name__ == "__main__":
    centers, radii, sum_radii = run_packing()
    print(f"Sum of radii: {sum_radii}")
